    @property
    def registry(self) -> HandlerRegistry:
        return self._registry

    def _parse_message(self, message: dict) -> Optional[MessageContext]:
        message_id = message.get("MessageId", "unknown")
        receipt_handle = message.get("ReceiptHandle")
        body_raw = message.get("Body", "")

        if not receipt_handle:
            logger.error(f"Message {message_id} missing ReceiptHandle")
            return None

        if len(body_raw) > self.MAX_MESSAGE_BODY_SIZE:
            logger.error(f"Message {message_id} body exceeds maximum size")
            return None

        try:
            body = json.loads(body_raw)
        except (json.JSONDecodeError, TypeError) as e:
            logger.error(f"Failed to parse message {message_id} body as JSON: {e}")
            return None

        if not isinstance(body, dict):
            logger.error(f"Message {message_id} body is not a JSON object")
            return None

        message_type = body.get("message_type")
        if not message_type or not isinstance(message_type, str):
            logger.error(f"Message {message_id} missing or invalid 'message_type' field")
            return None

        if len(message_type) > self.ALLOWED_MESSAGE_TYPES_PATTERN_MAX_LEN:
            logger.error(f"Message {message_id} has excessively long message_type")
            return None

        # Sanitize: only allow alphanumeric, underscore, hyphen
